using System;

class Program
{
    static void Main()
    {
        int a = 42;
        double b = 3.14;
        decimal c = 19.99m;

        Console.WriteLine($"int: {a}");
        Console.WriteLine($"double: {b}");
        Console.WriteLine($"decimal: {c}");
        Console.WriteLine($"Max of 10 and 20: {Math.Max(10, 20)}");
        Console.WriteLine($"Round 3.14159: {Math.Round(3.14159, 2)}");
        Console.WriteLine($"2^10: {Math.Pow(2, 10)}");
    }
}
